// ❌ Sync I/O on main
fun loadConfig(): String = File("/sdcard/config.json").readText()

// ✅ Off-main with coroutines
suspend fun loadConfig(): String = withContext(Dispatchers.IO) {
  File(filesDir, "config.json").readText()
}

// ✅ ViewModel pattern — no main blocking
class FeedVM(private val repo: FeedRepo) : ViewModel() {
  fun reload() = viewModelScope.launch {
    val items = repo.fetch()                 // suspend, off-main internally
    _state.value = items
  }
}

// StrictMode — catch dev-time mistakes
if (BuildConfig.DEBUG) {
  StrictMode.setThreadPolicy(StrictMode.ThreadPolicy.Builder()
    .detectDiskReads()
    .detectDiskWrites()
    .detectNetwork()
    .penaltyLog()
    .penaltyDeath()
    .build()
  )
  StrictMode.setVmPolicy(StrictMode.VmPolicy.Builder()
    .detectLeakedClosableObjects()
    .detectActivityLeaks()
    .penaltyLog()
    .build()
  )
}

