// ❌ Static reference to Activity = leak
object Cache {
  var ctx: Context? = null     // accidentally an Activity
}
class MainActivity : ComponentActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    Cache.ctx = this           // 💥 leaks MainActivity forever
  }
}

// ✅ App context is fine
Cache.ctx = applicationContext

// ❌ Inner class captures outer Activity
class MainActivity : ComponentActivity() {
  inner class Tick : Runnable { override fun run() { /* uses outer this */ } }
  // Tick has implicit reference to MainActivity. If it lives in a long-lived handler, leak.
}

// ✅ Use static / weak
class StaticTick(activity: MainActivity) : Runnable {
  private val ref = WeakReference(activity)
  override fun run() {
    val a = ref.get() ?: return
    // ...
  }
}

// ✅ Coroutines tied to lifecycle
lifecycleScope.launch {
  // auto-cancelled when the lifecycle owner is destroyed
}

// Kotlin gotcha: storing a lambda referencing `this` is the same trap
class MainActivity : ComponentActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    GlobalEvents.subscribe { onResize() }   // ⚠️ leak if not unsubscribed
  }
}

// JankStats — track frame durations
import androidx.metrics.performance.JankStats
import androidx.metrics.performance.PerformanceMetricsState

class MainActivity : ComponentActivity() {
  private lateinit var jankStats: JankStats
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    jankStats = JankStats.createAndTrack(window) { frameData ->
      if (frameData.isJank) {
        Analytics.track("jank", mapOf("durationMs" to frameData.frameDurationUiNanos / 1_000_000))
      }
    }
    PerformanceMetricsState.getHolderForHierarchy(window.decorView)
      .state?.putState("screen", "home")
  }
}

// Compose — reduce recomposition and offload work
@Composable fun ImageRow(url: String) {
  AsyncImage(
    model = url,
    contentDescription = null,
    contentScale = ContentScale.Crop,
    modifier = Modifier.size(48.dp)
  )                                              // Coil decodes off-main
}

// RecyclerView with DiffUtil
class MyAdapter : ListAdapter<Item, RowVH>(diff) {
  override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
    RowVH(LayoutInflater.from(parent.context).inflate(R.layout.row, parent, false))
  override fun onBindViewHolder(holder: RowVH, position: Int) = holder.bind(getItem(position))
  companion object { val diff = object : DiffUtil.ItemCallback<Item>() {
    override fun areItemsTheSame(o: Item, n: Item) = o.id == n.id
    override fun areContentsTheSame(o: Item, n: Item) = o == n
  } }
}

