// proguard-rules.pro — examples
# Keep model classes used by reflection (Gson / kotlinx serialization handles via plugin)
-keep class com.app.dto.** { *; }

# Keep enum values (Gson + reflection)
-keepclassmembers enum * {
  public static **[] values();
  public static ** valueOf(java.lang.String);
}

# Don't strip serialization annotations
-keepattributes *Annotation*,Signature

# Don't obfuscate the app's package layout (sometimes useful for crash analytics)
# -keepnames class com.app.** { *; }

# Native methods
-keepclasseswithmembernames class * {
  native <methods>;
}

