// AppStartup library — declarative initializers
// build.gradle: implementation("androidx.startup:startup-runtime:1.1.1")

class AnalyticsInitializer : Initializer<AnalyticsClient> {
  override fun create(context: Context): AnalyticsClient {
    return AnalyticsClient.init(context).also { it.start() }
  }
  override fun dependencies(): List<Class<out Initializer<*>>> = emptyList()
}

// Manifest entry — runs the initializer ONCE in a controlled order
// <provider
//   android:name="androidx.startup.InitializationProvider"
//   android:authorities="${applicationId}.androidx-startup"
//   tools:node="merge">
//   <meta-data android:name="com.app.AnalyticsInitializer"
//              android:value="androidx.startup" />
// </provider>

// Defer non-critical work to first idle frame
class MyApp : Application() {
  override fun onCreate() {
    super.onCreate()
    Looper.myQueue().addIdleHandler {
      AnalyticsClient.init(this).start()
      ImageLoader.warmup()
      false
    }
  }
}

